function IdTipoLancamento_onChange()
{
$_SESSION['scriptcase']['LancamentoReceita_Frm']['contr_erro'] = 'on';
  
$original_idcontacaixa = $this->idcontacaixa;
$original_contacontabil = $this->contacontabil;

$check_sql = "SELECT IdContaCaixa, TipoClassificacao, ContaContabil"
   . " FROM tipolancamento"
   . " WHERE IdTipoLancamento = " . $idtipolancamento ;
 
      $nm_select = $check_sql; 
      $_SESSION['scriptcase']['sc_sql_ult_comando'] = $nm_select; 
      $_SESSION['scriptcase']['sc_sql_ult_conexao'] = ''; 
      $this->rs = array();
      if ($SCrx = $this->Db->Execute($nm_select)) 
      { 
          $SCy = 0; 
          $nm_count = $SCrx->FieldCount();
          while (!$SCrx->EOF)
          { 
                 for ($SCx = 0; $SCx < $nm_count; $SCx++)
                 { 
                      $this->rs[$SCy] [$SCx] = $SCrx->fields[$SCx];
                 }
                 $SCy++; 
                 $SCrx->MoveNext();
          } 
          $SCrx->Close();
      } 
      elseif (isset($GLOBALS["NM_ERRO_IBASE"]) && $GLOBALS["NM_ERRO_IBASE"] != 1)  
      { 
          $this->rs = false;
          $this->rs_erro = $this->Db->ErrorMsg();
      } 


if (isset($this->rs[0][0])) {
    $this->idcontacaixa     = $this->rs[0][0];
    $tipoclassificacao     = $this->rs[0][1];
    $this->contacontabil  = $this->rs[0][2];
}

$modificado_idcontacaixa = $this->idcontacaixa;
