   function SC_fast_search($in_fields, $arg_search, $data_search)
   {
      $fields = (strpos($in_fields, "SC_all_Cmp") !== false) ? array("SC_all_Cmp") : explode(";", $in_fields);
      $this->NM_case_insensitive = true;
      if (empty($data_search)) 
      {
         unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['dyn_search_and_or']);
         unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['dyn_search_cache']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['where_filter']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['total']);
          unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['fast_search']);
          if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['where_detal']) && !empty($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['where_detal'])) 
          {
              $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['where_filter'] = $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['where_detal'];
          }
          if (isset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['empty_filter']) && $_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['empty_filter'])
          {
              unset($_SESSION['sc_session'][$this->Ini->sc_page]['LancamentoReceita_Frm']['empty_filter']);
              $this->NM_ajax_info['empty_filter'] = 'ok';
              LancamentoReceita_Frm_pack_ajax_response();
              exit;
          }
          return;
      }
      $comando = "";
      if ($_SESSION['scriptcase']['charset'] != "UTF-8" && NM_is_utf8($data_search))
      {
